function App() {
  return (
    <Routes>
      <Route path="/" element={<Layout />}>
        <Route index element={<Home />} />
        <Route path="users" element={<UsersLayout />}>
          <Route index element={<UserList />} />
          <Route path=":userId" element={<UserDetail />} />
        </Route>
      </Route>
    </Routes>
  );
}

function UsersLayout() {
  return (
    <div>
      <aside>Users navigation</aside>
      <Outlet />
    </div>
  );
}
